create table dirkspzm32.bde_pd_rueckverfolgung (
    sid                 varchar2(2 char) not null enable,
    abfr_id             number(*, 0) not null enable,
    abfr_typ            varchar2(2 char) not null enable,
    abfr_zeile          number(*, 5) not null enable,
    abfr_parent_zeile   number(*, 5),
    firma_nr            number(2, 0),
    leitzahl            number(*, 5),
    fa_ag               number(*, 5),
    fa_upos             number(*, 5),
    res_id              number(*, 0),
    pers_nr             number(*, 0),
    user_id             number(*, 0),
    lam_id              number(*, 0),
    artikel_id          number(*, 0),
    change_id           number(*, 0),
    serie_id            number(*, 0),
    best_nr             varchar2(20 char),
    best_pos            varchar2(5 char),
    prod_datum          date,
    zug_datum           date,
    lte_id              varchar2(20 char),
    lhm_id              varchar2(20 char),
    menge               number(*, 3),
    mengeneinheit_basis varchar2(10 char) default 'STK',
    gewicht_kg          number(*, 3),
    zeichnung           varchar2(255 char),
    zeichnung_index     varchar2(10 char),
    li_nr_lief          varchar2(20 char),
    lieferant_nr        varchar2(20 char),
    lte_id_lieferant    varchar2(20 char),
    sonst_id_lieferant  varchar2(20 char),
    quell_lte_id        varchar2(20 char),
    quell_lhm_id        varchar2(20 char)
);

alter table dirkspzm32.bde_pd_rueckverfolgung
    add constraint pk_bde_pd_rueckverfolgung
        primary key ( sid,
                      abfr_id,
                      abfr_zeile )
            using index enable;


